// src/auto-iteration.ts

import { getServices } from './dashboard/server';

export class AutoIterationEngine {
  private dashboardServices = getServices();

  // 在迭代开始时通知 Dashboard
  async notifyIterationStart(iteration: Iteration) {
    await this.dashboardServices.iterationService.create({
      iterationNumber: this.count,
      status: 'running',
      requirement: iteration.requirement
    });

    // WebSocket 推送
    this.dashboardServices.realtimeService.broadcast('iteration.started', {
      id: iteration.id,
      number: this.count
    });
  }

  // 在迭代进度更新时通知
  async notifyProgress(phase: string, progress: number, message: string) {
    this.dashboardServices.realtimeService.broadcast('iteration.progress', {
      phase,
      progress,
      message,
      timestamp: new Date()
    });
  }

  // 在 Agent 状态变化时通知
  async notifyAgentStatus(agentName: string, status: string, data: any) {
    this.dashboardServices.realtimeService.broadcast('agent.status_changed', {
      name: agentName,
      status,
      ...data
    });
  }

  // 在迭代完成时通知
  async notifyIterationComplete(result: IterationResult) {
    await this.dashboardServices.iterationService.update(this.currentId, {
      status: result.success ? 'completed' : 'failed',
      completedAt: new Date(),
      durationSeconds: Math.floor((Date.now() - this.startTime) / 1000),
      output: result.output
    });
  }
}
```

