// 文件: src/dashboard/services/system.service.ts

export class SystemService {
  // 1. 完善 getSystemOverview 方法
  async getSystemOverview(): Promise<SystemOverview> {
    const [iterationStats, agentStats, activeIteration] = await Promise.all([
      this.iterationService.getStats(30),
      this.agentService.getPerformanceStats(30),
      this.iterationService.findRunning()
    ])

    return {
      totalIterations: iterationStats.total,
      runningIterations: activeIteration ? 1 : 0,
      completedIterations: iterationStats.completed,
      failedIterations: iterationStats.failed,
      successRate: iterationStats.successRate,
      averageDuration: iterationStats.averageDuration,
      activeAgents: agentStats.filter(a => a.status === 'running').length,
      currentIteration: activeIteration
    }
  }

  // 2. 实现 getMetrics 方法
  async getMetrics(period: string = '24h'): Promise<SystemMetricsResponse> {
    const startDate = this.parsePeriod(period)

    // 从数据库获取指标
    const metrics = this.db.prepare(`
      SELECT * FROM system_metrics
      WHERE recorded_at >= ?
      ORDER BY recorded_at ASC
    `).all(startDate.toISOString())

    // 转换为图表数据格式
    return {
      timestamps: metrics.map(m => m.recorded_at),
      cpu: metrics.map(m => m.cpu_usage_percent),
      memory: metrics.map(m => m.memory_usage_mb),
      activeIterations: metrics.map(m => m.active_iterations),
      apiCalls: metrics.map(m => m.api_calls_today)
    }
  }

  // 3. 实现指标收集定时器
  startMetricsCollection(intervalMs: number = 5000) {
    setInterval(() => {
      this.collectCurrentMetrics()
    }, intervalMs)
  }

  private collectCurrentMetrics() {
    const metrics = {
      recorded_at: new Date().toISOString(),
      cpu_usage_percent: process.cpuUsage().system / 1000000,
      memory_usage_mb: process.memoryUsage().heapUsed / 1024 / 1024,
      memory_heap_used_mb: process.memoryUsage().heapUsed / 1024 / 1024,
      memory_heap_total_mb: process.memoryUsage().heapTotal / 1024 / 1024,
      active_connections: this.websocketService?.getConnectionCount() || 0,
      active_websockets: this.websocketService?.getConnectionCount() || 0,
      active_iterations: this.iterationService.findRunning() ? 1 : 0
    }

    this.db.prepare(`
      INSERT INTO system_metrics (
        recorded_at, cpu_usage_percent, memory_usage_mb,
        memory_heap_used_mb, memory_heap_total_mb,
        active_connections, active_websockets, active_iterations
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?)
    `).run(
      metrics.recorded_at,
      metrics.cpu_usage_percent,
      metrics.memory_usage_mb,
      metrics.memory_heap_used_mb,
      metrics.memory_heap_total_mb,
      metrics.active_connections,
      metrics.active_websockets,
      metrics.active_iterations
    )

    // 广播指标
    this.realtimeService?.broadcastSystemMetrics(metrics)
  }
}
