// 文件: src/dashboard/services/realtime.service.ts

export class RealtimeService {
  private clients: Set<WebSocket> = new Set()
  private subscriptions: Map<string, Set<WebSocket>> = new Map()

  // 1. 完善连接管理
  addClient(client: WebSocket) {
    this.clients.add(client)

    client.on('close', () => {
      this.removeClient(client)
    })
  }

  removeClient(client: WebSocket) {
    this.clients.delete(client)
    // 清理订阅
    for (const [channel, subscribers] of this.subscriptions) {
      subscribers.delete(client)
    }
  }

  // 2. 实现频道订阅
  subscribe(client: WebSocket, channel: string) {
    if (!this.subscriptions.has(channel)) {
      this.subscriptions.set(channel, new Set())
    }
    this.subscriptions.get(channel)!.add(client)
  }

  // 3. 实现广播方法
  broadcastIterationStatusChange(data: any) {
    this.broadcast('iteration.status_changed', data)
  }

  broadcastAgentStatusChange(data: any) {
    this.broadcast('agent.status_changed', data)
  }

  broadcastIterationProgress(data: any) {
    this.broadcast('iteration.progress', data)
  }

  broadcastSystemMetrics(data: any) {
    this.broadcast('system.metrics', data)
  }

  private broadcast(event: string, data: any) {
    const message = JSON.stringify({ event, data })

    this.clients.forEach(client => {
      if (client.readyState === WebSocket.OPEN) {
        client.send(message)
      }
    })
  }

  // 4. 实现定向推送（推送到特定频道订阅者）
  publish(channel: string, event: string, data: any) {
    const subscribers = this.subscriptions.get(channel)
    if (!subscribers) return

    const message = JSON.stringify({ event, data })

    subscribers.forEach(client => {
      if (client.readyState === WebSocket.OPEN) {
        client.send(message)
      }
    })
  }
}
```

