<script setup lang="ts">
import { ref, computed, onMounted, onUnmounted, nextTick } from 'vue'
import { useWebSocketStore } from '@/stores/websocket'

const wsStore = useWebSocketStore()
const logs = ref<any[]>([])
const filterLevel = ref('all')
const searchKeyword = ref('')
const autoScroll = ref(true)
const logContainer = ref<HTMLElement>()

// 过滤日志
const filteredLogs = computed(() => {
  return logs.value.filter(log => {
    const matchLevel = filterLevel.value === 'all' || log.level === filterLevel.value
    const matchKeyword = !searchKeyword.value || 
      log.message.toLowerCase().includes(searchKeyword.value.toLowerCase())
    return matchLevel && matchKeyword
  })
})

// 格式化时间
function formatTime(timestamp: string) {
  return new Date(timestamp).toLocaleTimeString('zh-CN')
}

// 导出日志
function handleExport() {
  const content = filteredLogs.value.map(log => 
    `${formatTime(log.timestamp)} [${log.level.toUpperCase()}] ${log.message}`
  ).join('\n')

  const blob = new Blob([content], { type: 'text/plain' })
  const url = URL.createObjectURL(blob)
  const a = document.createElement('a')
  a.href = url
  a.download = `logs-${Date.now()}.txt`
  a.click()
  URL.revokeObjectURL(url)
}

// 监听 WebSocket 日志事件
onMounted(() => {
  wsStore.connect()

  wsStore.on('log.message', (data: any) => {
    logs.value.push({
      id: Date.now() + Math.random(),
      timestamp: data.timestamp,
      level: data.level,
      message: data.message
    })

    // 限制最大日志数量
    if (logs.value.length > 1000) {
      logs.value = logs.value.slice(-1000)
    }

    // 自动滚动
    if (autoScroll.value) {
      nextTick(() => {
        if (logContainer.value) {
          logContainer.value.scrollTop = logContainer.value.scrollHeight
        }
      })
    }
  })
})

onUnmounted(() => {
  wsStore.off('log.message')
  wsStore.disconnect()
})
</script>

