class AutoIterationEngine {
  async executeAgentWithRetry(
    agent: BaseAgent, 
    task: string, 
    maxRetries: number = 3
  ) {
    let lastError: Error
    for (let i = 0; i < maxRetries; i++) {
      try {
        return await agent.execute(task)
      } catch (error) {
        lastError = error
        if (i < maxRetries - 1) {
          await this.delay(Math.pow(2, i) * 1000) // 指数退避
        }
      }
    }
    throw lastError
  }
}
```

